def merge_within(pairs):
    if not pairs:
        return []

    merged = [sorted(pairs[0])]
    for start, end in sorted(pairs[1:], key=lambda x: (x[0], -x[1])):
        if start <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], end)
        else:
            merged.append([start, end])

    return merged
